// 분류 커스텀 아이콘 (투명 알파 마스크, CSS mask-image). 96px.
export const CAT_ICON_IMG = {
  block: 'data:image/png;base64,',
  accom: 'data:image/png;base64,',
  pipe: 'data:image/png;base64,',
  lashing: 'data:image/png;base64,',
  hatch: 'data:image/png;base64,',
}

// 마스크 CSS를 <style>로 한 번만 주입 (요소마다 base64 중복 방지)
if (typeof document !== 'undefined' && !document.querySelector('style[data-cat-icons]')) {
  const css = Object.entries(CAT_ICON_IMG)
    .map(([k, url]) => `.cat-ic.ci-${k}{-webkit-mask-image:url("${url}");mask-image:url("${url}")}`)
    .join('')
  const style = document.createElement('style')
  style.setAttribute('data-cat-icons', '')
  style.textContent = css
  document.head.appendChild(style)
}
